// Game state
let board = Array(9).fill(null);
let currentPlayer = 'X';
let gameOver = false;

// Win conditions: array of indices that form a winning line
const winConditions = [
    [0, 1, 2], // rows
    [3, 4, 5],
    [6, 7, 8],
    [0, 3, 6], // columns
    [1, 4, 7],
    [2, 5, 8],
    [0, 4, 8], // diagonals
    [2, 4, 6]
];

/**
 * Check if there's a winner
 * @param {Array<string|null>} gameBoard - Current game board
 * @returns {string|null} 'X', 'O', or null
 */
function checkWinner(gameBoard) {
    for (const [a, b, c] of winConditions) {
        if (gameBoard[a] &&
            gameBoard[a] === gameBoard[b] &&
            gameBoard[a] === gameBoard[c]) {
            return gameBoard[a];
        }
    }
    return null;
}

/**
 * Check if the game is a draw
 * @param {Array<string|null>} gameBoard - Current game board
 * @returns {boolean} True if board is full and no winner
 */
function checkDraw(gameBoard) {
    return gameBoard.every(cell => cell !== null) && checkWinner(gameBoard) === null;
}

/**
 * Make a move on the board
 * @param {number} index - Board index (0-8)
 * @param {string} player - 'X' or 'O'
 * @returns {boolean} True if move was successful
 */
function makeMove(index, player) {
    if (board[index] !== null || gameOver) {
        return false;
    }

    board[index] = player;

    if (checkWinner(board) || checkDraw(board)) {
        gameOver = true;
    }

    return true;
}

/**
 * Switch to the next player
 */
function switchPlayer() {
    currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
}

/**
 * Reset the game to initial state
 */
function resetGame() {
    board = Array(9).fill(null);
    currentPlayer = 'X';
    gameOver = false;
}

/**
 * Get the current game board
 * @returns {Array<string|null>}
 */
function getBoard() {
    return [...board];
}

/**
 * Get the current player
 * @returns {string} 'X' or 'O'
 */
function getCurrentPlayer() {
    return currentPlayer;
}

/**
 * Check if game is over
 * @returns {boolean}
 */
function isGameOver() {
    return gameOver;
}

// DOM interaction
document.addEventListener('DOMContentLoaded', () => {
    const cells = document.querySelectorAll('.cell');
    const turnIndicator = document.getElementById('turnIndicator');
    const winnerDisplay = document.getElementById('winnerDisplay');
    const resetButton = document.getElementById('resetButton');

    function updateUI() {
        // Update cells
        cells.forEach((cell, index) => {
            cell.textContent = board[index];
        });

        // Update turn indicator
        const winner = checkWinner(board);
        const isDraw = checkDraw(board);

        if (winner) {
            turnIndicator.textContent = '';
            winnerDisplay.textContent = `🎉 Player ${winner} Wins!`;
            winnerDisplay.classList.add('show');
        } else if (isDraw) {
            turnIndicator.textContent = '';
            winnerDisplay.textContent = "🤝 It's a Draw!";
            winnerDisplay.classList.add('show');
        } else {
            turnIndicator.textContent = `Player ${currentPlayer}'s Turn`;
            winnerDisplay.textContent = '';
            winnerDisplay.classList.remove('show');
        }
    }

    // Handle cell clicks
    cells.forEach((cell, index) => {
        cell.addEventListener('click', () => {
            if (makeMove(index, currentPlayer)) {
                updateUI();

                if (!isGameOver()) {
                    switchPlayer();
                    updateUI();
                }
            }
        });
    });

    // Handle reset button
    resetButton.addEventListener('click', () => {
        resetGame();
        updateUI();
    });

    // Initial UI
    updateUI();
});

// Export for testing
if (typeof module !== 'undefined' && module.exports) {
    module.exports = {
        checkWinner,
        checkDraw,
        makeMove,
        resetGame,
        getBoard,
        getCurrentPlayer,
        switchPlayer,
        isGameOver
    };
}

